custom_css:
#fallback-title {
    position: relative;
    display: inline-block;
    color: #fff;
    text-shadow: 0 0 15px rgba(255,255,255,0.5);
    z-index: 10;
    font-size: 24px;
    letter-spacing: -1px;
}

#custom-logo-container {
    position: relative;
    overflow: hidden;
    padding: 10px 20px;
    background: rgba(255, 255, 255, 0.05);
    border-radius: 12px;
}

#custom-logo-container::before {
    content: '';
    position: absolute;
    top: -50px;
    left: 0;
    width: 100%;
    height: 200%;
    background-image: 
        radial-gradient(circle, #fff 10%, transparent 20%),
        radial-gradient(circle, #fff 10%, transparent 20%);
    background-position: 0 0, 50px 50px;
    background-size: 100px 100px;
    animation: snowFall 4s linear infinite;
    opacity: 0.6;
    pointer-events: none;
}

#custom-logo-container::after {
    content: '';
    position: absolute;
    top: -60px;
    left: 20%;
    width: 15px;
    height: 15px;
    background: #ef4444;
    box-shadow: 
        inset 0 6px 0 0 #fee2e2, 
        inset 6px 0 0 0 #fee2e2,
        40px 100px 0 #10b981,
        40px 106px 0 0 #fef08a;
    animation: snowFall 6s linear infinite;
    animation-delay: 2s;
    opacity: 0.8;
}

@keyframes snowFall {
    0% { transform: translateY(0) rotate(0deg); }
    100% { transform: translateY(50px) rotate(10deg); }
}

header {
    background: linear-gradient(to bottom, rgba(15, 23, 42, 0.8), transparent);
}
